        if (_priceType == PriceType.ETHER) {
            require(msg.value >= price, "Insufficient ETH is transferred to purchase!");
            _owner.transfer(fee);
            nftOwner.transfer(amountAfterFee);
            // in case extra ETH is transferred, forward the extra to owner
